import{_ as i,C as e,o as n,c as p,j as l,a as r,E as t,ag as o}from"./chunks/framework.CAXxHpAX.js";const k=JSON.parse('{"title":"17. 最终学习目标","description":"定义从会查数据到会构建智能数据系统的最终能力标准。","frontmatter":{"title":"17. 最终学习目标","description":"定义从会查数据到会构建智能数据系统的最终能力标准。","prev":{"text":"16. 能力地图","link":"/chapters/16-capability-map"},"next":false},"headers":[],"relativePath":"chapters/17-final-goals.md","filePath":"chapters/17-final-goals.md"}'),c={name:"chapters/17-final-goals.md"};function h(d,a,u,b,m,g){const s=e("Mermaid");return n(),p("div",null,[a[0]||(a[0]=l("h1",{id:"_17-最终学习目标",tabindex:"-1"},[r("17. 最终学习目标 "),l("a",{class:"header-anchor",href:"#_17-最终学习目标","aria-label":'Permalink to "17. 最终学习目标"'},"​")],-1)),a[1]||(a[1]=l("div",{class:"tip custom-block"},[l("p",{class:"custom-block-title"},"本章导读"),l("p",null,"定义从会查数据到会构建智能数据系统的最终能力标准。")],-1)),t(s,{code:"flowchart%20LR%0A%20%20A%5B%22%E4%BC%9A%E6%9F%A5%E6%95%B0%E6%8D%AE%22%5D%20--%3E%20B%5B%22%E7%90%86%E8%A7%A3%E6%95%B0%E6%8D%AE%E7%BB%93%E6%9E%84%22%5D%0A%20%20B%20--%3E%20C%5B%22%E8%AE%BE%E8%AE%A1%E6%95%B0%E6%8D%AE%E9%93%BE%E8%B7%AF%22%5D%0A%20%20C%20--%3E%20D%5B%22%E6%9E%84%E5%BB%BA%E5%88%86%E6%9E%90%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20D%20--%3E%20E%5B%22%E6%8E%A5%E5%85%A5%20AI%20%E6%A3%80%E7%B4%A2%22%5D%0A%20%20E%20--%3E%20F%5B%22%E6%B2%BB%E7%90%86%E4%B8%8E%E6%BC%94%E5%8C%96%22%5D%0A%20%20F%20--%3E%20G%5B%22%E4%BC%9A%E6%9E%84%E5%BB%BA%E6%99%BA%E8%83%BD%E6%95%B0%E6%8D%AE%E7%B3%BB%E7%BB%9F%22%5D%0A"}),a[2]||(a[2]=o(`<p>本书最终目标是把读者从：</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>会查数据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>带到：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>会构建智能数据系统</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个目标可以拆成十二项能力。</p><p>如果读者最后只是记住一堆名词，本书就没有完成任务。最终目标应该能被检查：给一个业务场景，读者能设计数据结构、分析口径、同步链路、计算层、查询层、AI 检索层和治理边界。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><p>最终能力不是“会用所有工具”，而是能围绕一个业务问题设计完整数据系统，并能说明每一层为什么出现、解决什么、不解决什么、如何验证。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="一、能用-postgresql-理解业务数据结构" tabindex="-1">一、能用 PostgreSQL 理解业务数据结构 <a class="header-anchor" href="#一、能用-postgresql-理解业务数据结构" aria-label="Permalink to &quot;一、能用 PostgreSQL 理解业务数据结构&quot;">​</a></h3><p>你应该能解释：</p><ul><li>Database、Schema、Table、Row、Column 的层级。</li><li>主键、外键、约束、事务、索引、视图、物化视图、分区的作用。</li><li>一张表的一行代表什么。</li><li>表之间如何通过业务关系连接。</li></ul><h3 id="二、能写复杂-sql-分析指标" tabindex="-1">二、能写复杂 SQL 分析指标 <a class="header-anchor" href="#二、能写复杂-sql-分析指标" aria-label="Permalink to &quot;二、能写复杂 SQL 分析指标&quot;">​</a></h3><p>你应该能使用：</p><ul><li>基础查询。</li><li>聚合。</li><li>JOIN。</li><li>CTE。</li><li>窗口函数。</li><li>指标 SQL。</li></ul><p>并能解释指标口径，而不是只给出 SQL 结果。</p><h3 id="三、能判断-postgresql-的分析边界" tabindex="-1">三、能判断 PostgreSQL 的分析边界 <a class="header-anchor" href="#三、能判断-postgresql-的分析边界" aria-label="Permalink to &quot;三、能判断 PostgreSQL 的分析边界&quot;">​</a></h3><p>你应该能区分：</p><ul><li>业务查询。</li><li>分析查询。</li><li>点查。</li><li>大范围扫描。</li><li>可以靠索引优化的问题。</li><li>应该迁移到 OLAP 或数仓的问题。</li></ul><h3 id="四、能设计数仓分层和指标体系" tabindex="-1">四、能设计数仓分层和指标体系 <a class="header-anchor" href="#四、能设计数仓分层和指标体系" aria-label="Permalink to &quot;四、能设计数仓分层和指标体系&quot;">​</a></h3><p>你应该能设计：</p><ul><li>ODS。</li><li>DWD。</li><li>DWS。</li><li>ADS。</li><li>事实表。</li><li>维度表。</li><li>指标字典。</li><li>指标血缘。</li></ul><h3 id="五、能理解-postgresql-到大数据平台的数据链路" tabindex="-1">五、能理解 PostgreSQL 到大数据平台的数据链路 <a class="header-anchor" href="#五、能理解-postgresql-到大数据平台的数据链路" aria-label="Permalink to &quot;五、能理解 PostgreSQL 到大数据平台的数据链路&quot;">​</a></h3><p>你应该能解释：</p><ul><li>ETL。</li><li>ELT。</li><li>CDC。</li><li>WAL。</li><li>Debezium。</li><li>Kafka Connect。</li><li>Airflow / Dagster。</li><li>数据质量检查。</li></ul><h3 id="六、能掌握主流系统的基本定位" tabindex="-1">六、能掌握主流系统的基本定位 <a class="header-anchor" href="#六、能掌握主流系统的基本定位" aria-label="Permalink to &quot;六、能掌握主流系统的基本定位&quot;">​</a></h3><p>你应该能判断：</p><ul><li>PostgreSQL 适合什么。</li><li>ClickHouse 适合什么。</li><li>Doris 适合什么。</li><li>Spark 适合什么。</li><li>Flink 适合什么。</li><li>Kafka 适合什么。</li><li>Iceberg 适合什么。</li><li>Trino 适合什么。</li><li>DuckDB 适合什么。</li></ul><h3 id="七、能理解向量数据库在-rag-和语义检索中的作用" tabindex="-1">七、能理解向量数据库在 RAG 和语义检索中的作用 <a class="header-anchor" href="#七、能理解向量数据库在-rag-和语义检索中的作用" aria-label="Permalink to &quot;七、能理解向量数据库在 RAG 和语义检索中的作用&quot;">​</a></h3><p>你应该能解释：</p><ul><li>Embedding。</li><li>Chunking。</li><li>Vector Search。</li><li>Metadata Filter。</li><li>Hybrid Search。</li><li>Rerank。</li><li>RAG Evaluation。</li><li>pgvector 与 Milvus / Qdrant 的边界。</li></ul><h3 id="八、能理解图数据库在知识图谱和关系分析中的作用" tabindex="-1">八、能理解图数据库在知识图谱和关系分析中的作用 <a class="header-anchor" href="#八、能理解图数据库在知识图谱和关系分析中的作用" aria-label="Permalink to &quot;八、能理解图数据库在知识图谱和关系分析中的作用&quot;">​</a></h3><p>你应该能解释：</p><ul><li>Node。</li><li>Edge。</li><li>Property Graph。</li><li>RDF。</li><li>Cypher。</li><li>多跳查询。</li><li>图算法。</li><li>知识图谱。</li><li>GraphRAG。</li></ul><h3 id="九、能设计批处理、实时处理、向量检索、图关系分析的综合架构" tabindex="-1">九、能设计批处理、实时处理、向量检索、图关系分析的综合架构 <a class="header-anchor" href="#九、能设计批处理、实时处理、向量检索、图关系分析的综合架构" aria-label="Permalink to &quot;九、能设计批处理、实时处理、向量检索、图关系分析的综合架构&quot;">​</a></h3><p>你应该能把系统串起来：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; CDC / Batch</span></span>
<span class="line"><span>  -&gt; Kafka / Spark / Flink</span></span>
<span class="line"><span>  -&gt; ClickHouse / Iceberg</span></span>
<span class="line"><span>  -&gt; Milvus / Neo4j</span></span>
<span class="line"><span>  -&gt; BI / RAG / GraphRAG</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>并能说明每一层的边界和职责。</p><h3 id="十、能理解数据湖与湖仓架构" tabindex="-1">十、能理解数据湖与湖仓架构 <a class="header-anchor" href="#十、能理解数据湖与湖仓架构" aria-label="Permalink to &quot;十、能理解数据湖与湖仓架构&quot;">​</a></h3><p>你应该能解释：</p><ul><li>Object Storage。</li><li>CSV / JSON / Avro / Parquet / ORC。</li><li>Iceberg / Delta / Hudi。</li><li>Catalog。</li><li>Spark / Flink / Trino 多引擎协作。</li></ul><h3 id="十一、能建立数据治理意识" tabindex="-1">十一、能建立数据治理意识 <a class="header-anchor" href="#十一、能建立数据治理意识" aria-label="Permalink to &quot;十一、能建立数据治理意识&quot;">​</a></h3><p>你应该能设计基础治理能力：</p><ul><li>元数据。</li><li>数据质量。</li><li>数据血缘。</li><li>指标治理。</li><li>权限安全。</li><li>向量数据治理。</li><li>图谱治理。</li><li>成本优化。</li></ul><h3 id="十二、能从-会查数据-升级为-会构建智能数据系统" tabindex="-1">十二、能从“会查数据”升级为“会构建智能数据系统” <a class="header-anchor" href="#十二、能从-会查数据-升级为-会构建智能数据系统" aria-label="Permalink to &quot;十二、能从“会查数据”升级为“会构建智能数据系统”&quot;">​</a></h3><p>最终能力不是某个单点技术。</p><p>而是能回答：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据从哪里来？</span></span>
<span class="line"><span>如何进入平台？</span></span>
<span class="line"><span>如何被组织？</span></span>
<span class="line"><span>如何被计算？</span></span>
<span class="line"><span>如何被查询？</span></span>
<span class="line"><span>如何被治理？</span></span>
<span class="line"><span>如何服务 BI、AI 和业务应用？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>如果你能围绕这些问题设计出一条清晰链路，并知道每个系统为什么出现、解决什么、不解决什么、和前后系统如何协作，那么你已经完成了本书的核心迁移。</p><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>本章是全书的最终验收标准。</p><p>它把前面章节的内容收束为三类产物：</p><ul><li><strong>理解产物</strong>：能解释概念、机制、边界和演化关系。</li><li><strong>设计产物</strong>：能画出架构、数据模型、链路和治理方案。</li><li><strong>验证产物</strong>：能用 SQL、任务、质量规则、评测集和复盘证明系统有效。</li></ul><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>给定一个“企业知识和经营分析平台”需求，最终读者应该能设计：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL：保存业务交易、用户、权限和元数据。</span></span>
<span class="line"><span>数仓：建设 ODS / DWD / DWS / ADS 和指标口径。</span></span>
<span class="line"><span>ETL / CDC：同步业务数据和变更事件。</span></span>
<span class="line"><span>Spark / Flink：处理离线历史和实时事件。</span></span>
<span class="line"><span>ClickHouse / Doris：服务 BI 和经营看板。</span></span>
<span class="line"><span>Iceberg Lakehouse：保存长期历史、日志、文档和 AI 中间产物。</span></span>
<span class="line"><span>pgvector / Milvus：构建 RAG 语义检索。</span></span>
<span class="line"><span>Neo4j / NebulaGraph：构建实体关系和 GraphRAG。</span></span>
<span class="line"><span>治理平台：统一质量、血缘、权限、指标和评测。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>并能解释每一层的边界：PostgreSQL 不承担全部历史分析，向量数据库不替代权限和事实校验，图数据库不替代关系型业务库，湖仓不替代所有高并发 OLAP 查询。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：最终目标是学完所有工具。</strong></p><p>工具永远会变化。最终目标是形成稳定的问题判断能力和系统迁移能力。</p><p><strong>误区二：能跑 Demo 就等于会构建系统。</strong></p><p>真实系统还需要数据质量、权限、血缘、失败恢复、成本控制和评测闭环。</p><p><strong>误区三：AI 数据系统是传统数据平台之外的新东西。</strong></p><p>AI 数据系统建立在传统数据平台之上，并增加文档、向量、图谱、评测和上下文治理。它不是跳过基础，而是扩展基础。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>用一页设计文档回答最终毕业题：</p><blockquote><p>为一个电商公司设计从 PostgreSQL 到 BI、RAG、GraphRAG 的智能数据系统。</p></blockquote><p>必须包含：</p><ul><li>数据源和业务表。</li><li>SQL 指标和口径。</li><li>数仓分层。</li><li>ETL / CDC 链路。</li><li>批处理和实时处理边界。</li><li>OLAP 查询服务。</li><li>湖仓存储。</li><li>向量检索。</li><li>图关系分析。</li><li>数据治理。</li><li>验收指标和风险边界。</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>这是全书最后一章，因此不再引出新的技术章节，而是把路线收束为一句话：数据库学习从 SQL 开始，但真正目标是理解数据如何成为可信、可计算、可检索、可治理的智能系统基础设施。</p><h2 id="结语" tabindex="-1">结语 <a class="header-anchor" href="#结语" aria-label="Permalink to &quot;结语&quot;">​</a></h2><p>数据库学习的起点可以是一条 SQL。</p><p>但数据系统理解的终点，不是写出更长的 SQL。</p><p>真正的终点是能理解数据如何从业务事实出发，经过建模、同步、计算、存储、检索、治理，最终成为 BI、RAG、GraphRAG、推荐、风控和智能应用可以依赖的基础设施。</p><p>这就是从 PostgreSQL 到智能数据系统的完整路径。</p>`,77))])}const A=i(c,[["render",h]]);export{k as __pageData,A as default};
